// shadcn
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";

// constants
const clients = [
  {
    name: "Shirley Hoe",
    role: "Professional",
    avatar: "https://cdn.uiable.com/block/team1.png",
    initials: "SH",
    text: "At half-past eight the door opened, the policeman appeared and requesting them to follow him.",
  },
  {
    name: "John Doe",
    role: "Professional",
    avatar: "https://cdn.uiable.com/block/team2.png",
    initials: "JD",
    text: "At half-past eight the door opened, the policeman appeared and requesting them to follow him.",
  },
  {
    name: "Joseph William",
    role: "Professional",
    avatar: "https://cdn.uiable.com/block/team3.png",
    initials: "JW",
    text: "At half-past eight the door opened, the policeman appeared and requesting them to follow him.",
  },
];

//  ------------------------------ | TESTIMONIAL 3 | ------------------------------  //

export default function Testimonial3() {
  return (
    <section className="py-20">
      <div className="container mx-auto px-6">
        <div className="grid grid-cols-12 mb-10">
          <div className="col-span-12 text-center">
            <h2>Our Clients</h2>
            <p className="text-muted-foreground mt-3 mx-auto max-w-3xl">
              At half-past eight the door opened, the policeman appeared, and
              requesting them to follow him, led the way to an adjoining hall.
            </p>
          </div>
        </div>
        <div className="grid grid-cols-12 gap-8">
          {clients.map((c, i) => (
            <div
              key={i}
              className="col-span-12 md:col-span-4 flex flex-col items-center text-center gap-2"
            >
              <Avatar className="h-25 w-25">
                <AvatarImage src={c.avatar} alt={c.name} />
                <AvatarFallback>{c.initials}</AvatarFallback>
              </Avatar>
              <h3 className="mt-2 mb-1">{c.name}</h3>
              <p className="text-muted-foreground mb-2">{c.role}</p>
              <p className="text-muted-foreground max-w-xs">{c.text}</p>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
